		Metadata:                promptMetadata,
		Tools:                   tools,
		ToolPreset:              preset,
		SelectedProvider:        selection.Provider,
		SelectedRoute:           selection.Route,
		RequestedModel:          selection.RequestedModel,
		ResolvedModel:           selection.ResolvedModel,
		ExplicitProvider:        *providerFlag != "",
		ExplicitModel:           *model != "",
		Policy:                  *policyFlag,
