func TestBuildServiceExecuteRequest_HarnessPolicyLeavesModelAndProviderUnsetUnlessExplicit(t *testing.T) {
	req := buildServiceExecuteRequest(serviceExecuteRequestParams{
		Prompt:           "hello",
